const LOGO_B64 = "/logo.png";

const TEAM_COLORS = {
  "A1 Gneiss":"#2563eb","A2 Shales":"#d97706","A3 Sandstones":"#16a34a",
  "A4 Greywackes":"#dc2626","A5 Gabbros":"#7c3aed","A6 Tuffs":"#0891b2",
  "A7 Basalts":"#ea580c","A8 Rhyolites":"#db2777","A9 Granites":"#65a30d"
};
const ALL_TEAMS = Object.keys(TEAM_COLORS);
const PLAYER_MAP = Object.fromEntries(PLAYERS.map(p => [p.pid, p]));

// ─── Position badge ───────────────────────────────────────────────────────────
// Rostered: baby blue, shows number only (strip the trailing S)
// Sub: amber/yellow, shows full positionPlayed string (e.g. "7S")
function PosBadge({ pos, isSub }) {
  const label = isSub ? pos : pos.replace(/S$/i, "");
  return isSub
    ? <span style={{background:"#fefce8",color:"#854d0e",border:"1px solid #fde047",borderRadius:4,padding:"1px 7px",fontSize:11,fontWeight:700,display:"inline-block",whiteSpace:"nowrap"}}>{label}</span>
    : <span style={{background:"#eff6ff",color:"#1d4ed8",border:"1px solid #bfdbfe",borderRadius:4,padding:"1px 7px",fontSize:11,fontWeight:700,display:"inline-block",whiteSpace:"nowrap"}}>{label}</span>;
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
const ratingDiff = (pr, or_) => (!pr||!or_) ? null : Math.round((or_-pr)*1000)/1000;

function RatingDiffBadge({ diff, size=12 }) {
  if (diff===null||diff===undefined) return <span style={{color:"#94a3b8",fontSize:size}}>—</span>;
  const pos=diff>0; const color=pos?"#16a34a":"#dc2626";
  return <span style={{color,fontWeight:600,fontSize:size,whiteSpace:"nowrap"}}>{pos?"+":""}{diff.toFixed(3)}</span>;
}

// Rating chip: shows current rating ONLY — no delta embedded
function RatingChip({ rating }) {
  if (!rating) return <span style={{color:"#94a3b8"}}>—</span>;
  return <span style={{background:"#f0fdf4",color:"#15803d",border:"1px solid #bbf7d0",borderRadius:4,padding:"1px 7px",fontSize:11,fontWeight:700}}>{rating.toFixed(3)}</span>;
}

function YouTubeIcon({ url, size=14 }) {
  if (!url) return null;
  return <a href={url} target="_blank" rel="noopener noreferrer" title="Watch on YouTube"
    style={{display:"inline-flex",alignItems:"center",textDecoration:"none",marginLeft:3,verticalAlign:"middle"}} onClick={e=>e.stopPropagation()}>
    <svg width={size+4} height={size} viewBox="0 0 28 20" fill="none">
      <rect width="28" height="20" rx="4" fill="#FF0000"/>
      <polygon points="11,5 22,10 11,15" fill="white"/>
    </svg>
  </a>;
}

function WinBar({ wins, losses }) {
  const total=wins+losses; const pct=total?(wins/total)*100:0;
  const color=pct>50?"#16a34a":pct===50?"#d97706":"#dc2626";
  return <div style={{display:"flex",alignItems:"center",gap:6}}>
    <div style={{flex:1,background:"#f1f5f9",height:5,borderRadius:3,overflow:"hidden",minWidth:50}}>
      <div style={{width:`${pct}%`,height:"100%",background:color,borderRadius:3}}/>
    </div>
    <span style={{fontSize:11,color,fontWeight:700,minWidth:30,textAlign:"right"}}>{pct.toFixed(0)}%</span>
  </div>;
}

function SortTh({ label, col, sortBy, sortDir, onSort, right }) {
  const active=sortBy===col;
  return <th style={{padding:"9px 11px",fontSize:11,fontWeight:700,color:"#64748b",textTransform:"uppercase",letterSpacing:0.4,borderBottom:"2px solid #e2e8f0",cursor:"pointer",whiteSpace:"nowrap",userSelect:"none",background:"#f8fafc",textAlign:right?"right":"left"}} onClick={()=>onSort(col)}>
    {label} {active?(sortDir===-1?"↓":"↑"):<span style={{opacity:0.25}}>↕</span>}
  </th>;
}

// ─── Styles ───────────────────────────────────────────────────────────────────
const S = {
  page:{fontFamily:"'Segoe UI',system-ui,sans-serif",background:"#f1f5f9",color:"#1e293b",minHeight:"100vh",fontSize:15},
  header:{background:"#1e3a5f",color:"#fff",padding:"0 28px",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8,minHeight:64},
  nav:{display:"flex",gap:6,alignItems:"center"},
  navBtn:(a)=>({background:a?"#fff":"transparent",color:a?"#1e3a5f":"#93c5fd",border:"1px solid",borderColor:a?"#fff":"#3b82f6",borderRadius:6,padding:"5px 14px",fontSize:13,fontWeight:600,cursor:"pointer"}),
  body:{maxWidth:1300,margin:"0 auto",padding:"20px 16px"},
  card:{background:"#fff",borderRadius:10,border:"1px solid #e2e8f0",boxShadow:"0 1px 3px rgba(0,0,0,0.06)"},
  th:{padding:"9px 11px",textAlign:"left",fontSize:11,fontWeight:700,color:"#64748b",textTransform:"uppercase",letterSpacing:0.4,borderBottom:"2px solid #e2e8f0",whiteSpace:"nowrap",background:"#f8fafc"},
  thR:{padding:"9px 11px",textAlign:"right",fontSize:11,fontWeight:700,color:"#64748b",textTransform:"uppercase",letterSpacing:0.4,borderBottom:"2px solid #e2e8f0",whiteSpace:"nowrap",background:"#f8fafc"},
  td:{padding:"8px 11px",borderBottom:"1px solid #f1f5f9",fontSize:13.5,verticalAlign:"middle"},
  tdR:{padding:"8px 11px",borderBottom:"1px solid #f1f5f9",fontSize:13.5,verticalAlign:"middle",textAlign:"right"},
  badge:(c)=>({background:c+"18",color:c,border:`1px solid ${c}44`,borderRadius:5,padding:"2px 9px",fontSize:11,fontWeight:600,display:"inline-block"}),
  resultW:{color:"#16a34a",fontWeight:700},
  resultL:{color:"#dc2626",fontWeight:700},
  pct:(v)=>({color:v>50?"#16a34a":v===50?"#d97706":"#dc2626",fontWeight:700}),
  input:{border:"1px solid #cbd5e1",borderRadius:7,padding:"7px 12px",fontSize:14,outline:"none",background:"#fff",color:"#1e293b"},
  select:{border:"1px solid #cbd5e1",borderRadius:7,padding:"7px 11px",fontSize:13,background:"#fff",color:"#1e293b",cursor:"pointer"},
  link:{color:"#2563eb",cursor:"pointer",textDecoration:"none",fontWeight:500,borderBottom:"1px solid #bfdbfe"},
  sectionTitle:{fontSize:16,fontWeight:700,color:"#1e293b",marginBottom:12},
  statBox:(a)=>({background:`${a}10`,border:`1px solid ${a}25`,borderRadius:8,padding:"11px 16px",textAlign:"center",flex:1,minWidth:85}),
  statVal:(a)=>({fontSize:22,fontWeight:800,color:a}),
  statLabel:{fontSize:10,color:"#64748b",letterSpacing:1.2,textTransform:"uppercase",marginTop:2},
  backBtn:{background:"none",border:"none",color:"#2563eb",cursor:"pointer",fontSize:14,fontWeight:600,padding:"4px 0",display:"flex",alignItems:"center",gap:4},
};

function minPosition(player, teamName) {
  const nums=player.match_list.filter(m=>m.team===teamName).map(m=>parseInt(m.position)).filter(n=>!isNaN(n));
  return nums.length?Math.min(...nums):99;
}

// Team badge: star for primary, normal weight always
function TeamBadge({ team, isPrimary, isSub, onClick }) {
  const color = TEAM_COLORS[team] || "#888";
  return <span onClick={onClick} style={{...S.badge(color),cursor:"pointer",fontWeight:600,
    border:isPrimary?`2px solid ${color}`:`1px solid ${color}44`}}>
    {isPrimary?"★ ":""}{team}
    {isSub&&<span style={{marginLeft:4,fontSize:10,opacity:0.8}}>(sub)</span>}
  </span>;
}

// ─── Scorecard Modal ──────────────────────────────────────────────────────────
function ScorecardModal({ scorecard, teamName, onClose, onPlayerClick }) {
  const isHome = scorecard.home_team===teamName;
  const color = TEAM_COLORS[teamName]||"#888";
  const myAvg = isHome?scorecard.home_avg_rating:scorecard.visit_avg_rating;
  const myRAvg = isHome?scorecard.home_roster_avg:scorecard.visit_roster_avg;
  const mySubs = isHome?scorecard.home_sub_count:scorecard.visit_sub_count;
  const subImpact = (myAvg&&myRAvg&&mySubs>0)?Math.round((myAvg-myRAvg)*1000)/1000:null;

  return <div style={{position:"fixed",inset:0,background:"rgba(15,23,42,0.65)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:12,width:"100%",maxWidth:840,maxHeight:"88vh",overflowY:"auto",boxShadow:"0 20px 60px rgba(0,0,0,0.3)"}}>
      <div style={{background:"#1e3a5f",color:"#fff",padding:"14px 20px",borderRadius:"12px 12px 0 0",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <div style={{fontWeight:700,fontSize:15}}>{scorecard.home_team} vs {scorecard.visit_team}</div>
          <div style={{fontSize:12,opacity:0.8,marginTop:2}}>{scorecard.matchdate} · {scorecard.matchtime} · #{scorecard.scorecardid}</div>
        </div>
        <button onClick={onClose} style={{background:"none",border:"none",color:"#fff",fontSize:20,cursor:"pointer",padding:4}}>✕</button>
      </div>
      <div style={{display:"flex",borderBottom:"1px solid #e2e8f0"}}>
        {[{team:scorecard.home_team,won:scorecard.home_won,avg:scorecard.home_avg_rating,rAvg:scorecard.home_roster_avg,subs:scorecard.home_sub_count,isUs:isHome},
          {team:scorecard.visit_team,won:scorecard.visit_won,avg:scorecard.visit_avg_rating,rAvg:scorecard.visit_roster_avg,subs:scorecard.visit_sub_count,isUs:!isHome}].map((side,i)=>(
          <div key={i} style={{flex:1,padding:"12px 20px",textAlign:"center",borderRight:i===0?"1px solid #e2e8f0":"none",background:side.isUs?`${color}08`:"#fafafa"}}>
            <div style={{fontSize:12,fontWeight:700,color:side.isUs?color:"#64748b",marginBottom:3}}>{side.team}{side.isUs?" ★":""}</div>
            <div style={{fontSize:30,fontWeight:800}}>{side.won}</div>
            <div style={{fontSize:11,color:"#94a3b8",marginTop:3}}>Avg: <b style={{color:"#15803d"}}>{side.avg?.toFixed(3)||"—"}</b>{side.subs>0&&<span style={{color:"#92400e"}}> · Roster: {side.rAvg?.toFixed(3)||"—"} ({side.subs} sub{side.subs>1?"s":""})</span>}</div>
          </div>
        ))}
      </div>
      {subImpact!==null&&<div style={{background:"#fffbeb",borderBottom:"1px solid #fde68a",padding:"7px 20px",fontSize:12,color:"#92400e"}}>
        <b>Sub rating impact:</b> Lineup avg {myAvg?.toFixed(3)} vs rostered-only {myRAvg?.toFixed(3)} → <RatingDiffBadge diff={subImpact} size={12}/>
        {subImpact>0?" (subs improved lineup)":" (subs lowered lineup)"}
      </div>}
      <table style={{width:"100%",borderCollapse:"collapse"}}>
        <thead><tr style={{background:"#f8fafc"}}>
          <th style={S.th}>Pos</th>
          <th style={{...S.th,color:TEAM_COLORS[scorecard.home_team]||"#333"}}>{scorecard.home_team}</th>
          <th style={S.thR}>Rating</th>
          <th style={{...S.th,textAlign:"center"}}>Score</th>
          <th style={S.thR}>Rating</th>
          <th style={{...S.th,color:TEAM_COLORS[scorecard.visit_team]||"#333"}}>{scorecard.visit_team}</th>
          <th style={{...S.th,textAlign:"center"}}>Result</th>
          <th style={{...S.th,textAlign:"center",width:36}}>▶</th>
        </tr></thead>
        <tbody>
          {scorecard.lineup.map((row,i)=>(
            <tr key={row.position} style={{background:i%2===0?"#fff":"#fafafa"}}>
              <td style={S.td}><PosBadge pos={row.position} isSub={false}/></td>
              <td style={S.td}>
                <span onClick={()=>{onClose();onPlayerClick(row.home_player_id);}} style={S.link}>{row.home_player_name}</span>
                {row.home_is_sub&&<span style={{marginLeft:5}}><PosBadge pos={row.position} isSub={true}/></span>}
              </td>
              <td style={S.tdR}><RatingChip rating={row.home_player_rating}/></td>
              <td style={{...S.td,textAlign:"center",fontFamily:"monospace",fontSize:11,whiteSpace:"nowrap"}}>{row.score}</td>
              <td style={S.tdR}><RatingChip rating={row.visit_player_rating}/></td>
              <td style={S.td}>
                <span onClick={()=>{onClose();onPlayerClick(row.visit_player_id);}} style={S.link}>{row.visit_player_name}</span>
                {row.visit_is_sub&&<span style={{marginLeft:5}}><PosBadge pos={row.position} isSub={true}/></span>}
              </td>
              <td style={{...S.td,textAlign:"center"}}><span style={row.home_won?S.resultW:S.resultL}>{row.home_won?"H":"V"}</span></td>
              <td style={{...S.td,textAlign:"center"}}><YouTubeIcon url={row.youtube}/></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  </div>;
}

// ─── Team Detail ──────────────────────────────────────────────────────────────
function TeamView({ teamName, onBack, onPlayerClick, savedState, onSaveState }) {
  const color=TEAM_COLORS[teamName];
  const [rs,setRs]=useState(savedState?.rs||"minPos"); const [rd,setRd]=useState(savedState?.rd||1);
  const [ms,setMs]=useState(savedState?.ms||"sort_key"); const [md,setMd]=useState(savedState?.md||1);
  const [modal,setModal]=useState(null);
  const save=(a,b,c,d)=>onSaveState({rs:a,rd:b,ms:c,md:d});
  const tRoster=col=>{const nd=rs===col?-rd:1;setRs(col);setRd(nd);save(col,nd,ms,md);};
  const tMatch=col=>{const nd=ms===col?-md:1;setMs(col);setMd(nd);save(rs,rd,col,nd);};

  const teamPlayers=PLAYERS.filter(p=>p.teams.includes(teamName));

  const rosterData=useMemo(()=>teamPlayers.map(p=>{
    const tm=p.match_list.filter(m=>m.team===teamName);
    const w=tm.filter(m=>m.result==="W").length,l=tm.length-w;
    const tPos={};
    for(const m of tm){
      if(!tPos[m.position])tPos[m.position]={wins:0,losses:0,diffs:[]};
      if(m.result==="W")tPos[m.position].wins++;else tPos[m.position].losses++;
      if(m.opponent_rating&&p.rating)tPos[m.position].diffs.push(m.opponent_rating-p.rating);
    }
    const rated=tm.filter(m=>m.opponent_rating&&p.rating);
    const avgDiff=rated.length>0?Math.round(rated.reduce((s,m)=>s+(m.opponent_rating-p.rating),0)/rated.length*1000)/1000:null;
    // sub = not in roster_teams for this team
    const isSub=!(p.roster_teams&&p.roster_teams[teamName]);
    const mp=minPosition(p,teamName);
    return {pid:p.pid,name:p.name,rating:p.rating,pre:p.pre_season_rating,rc:p.rating_change,matches:tm.length,wins:w,losses:l,pct:w+l>0?Math.round(w/(w+l)*100):0,positions:tPos,avgDiff,isSub,minPos:mp};
  }).sort((a,b)=>{
    if(rs==="name")return rd*a.name.localeCompare(b.name);
    const av=a[rs],bv=b[rs]; return rd*((av??999)-(bv??999));
  }),[teamPlayers,rs,rd]);

  const teamMatches=useMemo(()=>Object.entries(SCORECARDS)
    .filter(([,sc])=>sc.home_team===teamName||sc.visit_team===teamName)
    .map(([sid,sc])=>{
      const isHome=sc.home_team===teamName;
      const myWon=isHome?sc.home_won:sc.visit_won,oppWon=isHome?sc.visit_won:sc.home_won;
      const myAvg=isHome?sc.home_avg_rating:sc.visit_avg_rating;
      const myRAvg=isHome?sc.home_roster_avg:sc.visit_roster_avg;
      const oppAvg=isHome?sc.visit_avg_rating:sc.home_avg_rating;
      const subs=isHome?sc.home_sub_count:sc.visit_sub_count;
      return {sid,matchdate:sc.matchdate,matchtime:sc.matchtime,sort_key:sc.sort_key,
        isHome,oppTeam:isHome?sc.visit_team:sc.home_team,myWon,oppWon,myAvg,myRAvg,oppAvg,
        won:myWon>oppWon,ratingDiff:myAvg&&oppAvg?Math.round((myAvg-oppAvg)*1000)/1000:null,
        subImpact:myAvg&&myRAvg&&subs>0?Math.round((myAvg-myRAvg)*1000)/1000:null,
        subCount:subs,sc};
    }).sort((a,b)=>{
      const av=a[ms],bv=b[ms];
      if(typeof av==="string")return md*(av>bv?1:av<bv?-1:0);
      return md*((av??-999)-(bv??-999));
    }),[teamName,ms,md]);

  const totalW=teamMatches.filter(m=>m.won).length,totalL=teamMatches.length-totalW;
  const indiv=teamPlayers.flatMap(p=>p.match_list.filter(m=>m.team===teamName));
  const iW=indiv.filter(m=>m.result==="W").length;

  return <div>
    {modal&&<ScorecardModal scorecard={modal} teamName={teamName} onClose={()=>setModal(null)} onPlayerClick={pid=>{setModal(null);onPlayerClick(pid);}}/>}
    <button style={S.backBtn} onClick={onBack}>← Back</button>
    <div style={{marginTop:14,...S.card,padding:22}}>
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16}}>
        <div style={{width:12,height:36,borderRadius:3,background:color}}/>
        <div><h2 style={{margin:0,fontSize:20,fontWeight:800}}>{teamName}</h2>
          <div style={{fontSize:13,color:"#64748b"}}>PCS Maine Squash Winter League 2026</div></div>
      </div>
      <div style={{display:"flex",gap:10,marginBottom:20,flexWrap:"wrap"}}>
        {[{v:rosterData.length,l:"Players",c:color},{v:`${totalW}–${totalL}`,l:"Team Record",c:totalW>totalL?"#16a34a":"#dc2626"},{v:`${iW}–${indiv.length-iW}`,l:"Individual",c:"#6366f1"},{v:totalW+totalL>0?Math.round(totalW/(totalW+totalL)*100)+"%":"—",l:"Win%",c:"#0891b2"}].map(s=>(
          <div key={s.l} style={S.statBox(s.c)}><div style={{...S.statVal(s.c),fontSize:20}}>{s.v}</div><div style={S.statLabel}>{s.l}</div></div>
        ))}
      </div>

      {/* Roster */}
      <div style={{marginBottom:22}}>
        <div style={S.sectionTitle}>Roster</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:12.5}}>
            <thead><tr>
              <SortTh label="Pos" col="minPos" sortBy={rs} sortDir={rd} onSort={tRoster}/>
              <SortTh label="Player" col="name" sortBy={rs} sortDir={rd} onSort={tRoster}/>
              <SortTh label="Rating" col="rating" sortBy={rs} sortDir={rd} onSort={tRoster} right/>
              <SortTh label="Δ Rtg" col="rc" sortBy={rs} sortDir={rd} onSort={tRoster} right/>
              <SortTh label="MP" col="matches" sortBy={rs} sortDir={rd} onSort={tRoster} right/>
              <SortTh label="W" col="wins" sortBy={rs} sortDir={rd} onSort={tRoster} right/>
              <SortTh label="L" col="losses" sortBy={rs} sortDir={rd} onSort={tRoster} right/>
              <SortTh label="Win%" col="pct" sortBy={rs} sortDir={rd} onSort={tRoster} right/>
              <SortTh label="Opp Δ" col="avgDiff" sortBy={rs} sortDir={rd} onSort={tRoster} right/>
              <th style={{...S.th,whiteSpace:"nowrap"}}>Positions (W-L)</th>
            </tr></thead>
            <tbody>
              {rosterData.map((p,i)=>{
                const numPositions=Object.keys(p.positions).length;
                return <tr key={p.pid} style={{background:i%2===0?"#fff":"#fafafa"}}>
                  <td style={{...S.td,padding:"5px 8px"}}><PosBadge pos={`${p.minPos}S`} isSub={p.isSub}/></td>
                  <td style={{...S.td,padding:"5px 8px",fontSize:12.5,maxWidth:140,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                    <span onClick={()=>onPlayerClick(p.pid)} style={S.link}>{p.name}</span>
                  </td>
                  <td style={{...S.tdR,padding:"5px 8px"}}><RatingChip rating={p.rating}/></td>
                  <td style={{...S.tdR,padding:"5px 8px",fontSize:12}}>{p.rc!==null&&p.rc!==undefined?<RatingDiffBadge diff={p.rc}/>:<span style={{color:"#94a3b8"}}>—</span>}</td>
                  <td style={{...S.tdR,padding:"5px 6px",fontWeight:600}}>{p.matches}</td>
                  <td style={{...S.tdR,padding:"5px 6px",color:"#16a34a",fontWeight:700}}>{p.wins}</td>
                  <td style={{...S.tdR,padding:"5px 6px",color:"#dc2626",fontWeight:700}}>{p.losses}</td>
                  <td style={{...S.tdR,padding:"5px 8px",...S.pct(p.pct)}}>{p.pct}%</td>
                  <td style={{...S.tdR,padding:"5px 8px"}}><RatingDiffBadge diff={p.avgDiff}/></td>
                  <td style={{...S.td,padding:"5px 8px"}}>
                    <div style={{display:"flex",gap:3,flexWrap:numPositions>3?"wrap":"nowrap",alignItems:"center"}}>
                      {Object.entries(p.positions).sort().map(([pos,pd])=>{
                        const avgD=pd.diffs&&pd.diffs.length>0?Math.round(pd.diffs.reduce((a,b)=>a+b,0)/pd.diffs.length*1000)/1000:null;
                        return <span key={pos} style={{display:"inline-flex",alignItems:"center",gap:3,background:"#f8fafc",border:"1px solid #e2e8f0",borderRadius:4,padding:"2px 5px",whiteSpace:"nowrap"}}>
                          <PosBadge pos={pos} isSub={p.isSub}/>
                          <span style={{color:pd.wins>pd.losses?"#16a34a":pd.losses>pd.wins?"#dc2626":"#64748b",fontWeight:600,fontSize:11}}>{pd.wins}-{pd.losses}</span>
                          {avgD!==null&&<span style={{fontSize:10,color:"#64748b"}}>(<RatingDiffBadge diff={avgD} size={10}/>)</span>}
                        </span>;
                      })}
                    </div>
                  </td>
                </tr>;
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Match history */}
      <div>
        <div style={S.sectionTitle}>Match History</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead><tr>
              <SortTh label="Date" col="sort_key" sortBy={ms} sortDir={md} onSort={tMatch}/>
              <th style={S.th}>H/V</th>
              <th style={S.th}>Opponent</th>
              <SortTh label="Score" col="myWon" sortBy={ms} sortDir={md} onSort={tMatch} right/>
              <SortTh label="Roster Avg" col="myRAvg" sortBy={ms} sortDir={md} onSort={tMatch} right/>
              <SortTh label="Lineup Avg" col="myAvg" sortBy={ms} sortDir={md} onSort={tMatch} right/>
              <SortTh label="Opp Avg" col="oppAvg" sortBy={ms} sortDir={md} onSort={tMatch} right/>
              <SortTh label="Sub Δ" col="subImpact" sortBy={ms} sortDir={md} onSort={tMatch} right/>
              <SortTh label="Subs" col="subCount" sortBy={ms} sortDir={md} onSort={tMatch} right/>
              <SortTh label="Result" col="won" sortBy={ms} sortDir={md} onSort={tMatch}/>
              <th style={S.th}>Detail</th>
            </tr></thead>
            <tbody>
              {teamMatches.map((m,i)=>(
                <tr key={m.sid} style={{background:i%2===0?"#fff":"#fafafa"}}>
                  <td style={S.td}><span style={{fontSize:12}}>{m.matchdate}</span> <span style={{color:"#94a3b8",fontSize:11}}>{m.matchtime}</span></td>
                  <td style={S.td}><span style={{fontSize:11,fontWeight:700,color:m.isHome?"#2563eb":"#7c3aed"}}>{m.isHome?"HOME":"AWAY"}</span></td>
                  <td style={S.td}><span style={S.badge(TEAM_COLORS[m.oppTeam]||"#888")}>{m.oppTeam}</span></td>
                  <td style={{...S.tdR,fontWeight:700}}>{m.myWon}–{m.oppWon}</td>
                  <td style={S.tdR}>{m.myRAvg?<span style={{fontSize:12,fontWeight:600,color:"#0891b2"}}>{m.myRAvg.toFixed(3)}</span>:<span style={{color:"#94a3b8"}}>—</span>}</td>
                  <td style={S.tdR}>{m.myAvg?<b style={{fontSize:12,color:"#15803d"}}>{m.myAvg.toFixed(3)}</b>:<span style={{color:"#94a3b8"}}>—</span>}</td>
                  <td style={S.tdR}>{m.oppAvg?<span style={{fontSize:12,color:"#64748b"}}>{m.oppAvg.toFixed(3)}</span>:<span style={{color:"#94a3b8"}}>—</span>}</td>
                  <td style={S.tdR}>{m.subImpact!==null?<RatingDiffBadge diff={m.subImpact}/>:<span style={{color:"#94a3b8",fontSize:12}}>—</span>}</td>
                  <td style={S.tdR}>{m.subCount>0?<span style={{background:"#fefce8",color:"#854d0e",border:"1px solid #fde047",borderRadius:4,padding:"1px 7px",fontSize:11,fontWeight:700}}>{m.subCount}</span>:<span style={{color:"#94a3b8"}}>0</span>}</td>
                  <td style={S.td}><span style={m.won?S.resultW:S.resultL}>{m.won?"WIN":"LOSS"}</span></td>
                  <td style={S.td}><button onClick={()=>setModal(m.sc)} style={{background:"#eff6ff",color:"#2563eb",border:"1px solid #bfdbfe",borderRadius:5,padding:"3px 10px",fontSize:12,cursor:"pointer",fontWeight:600}}>View →</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  </div>;
}

// ─── Player Detail ─────────────────────────────────────────────────────────────
function PlayerView({ player, onBack, onTeamClick, onPlayerClick, savedState, onSaveState }) {
  const [tf,setTf]=useState(savedState?.tf||"ALL"); const [pf,setPf]=useState(savedState?.pf||"ALL");
  const [sb,setSb]=useState(savedState?.sb||"sort_key"); const [sd,setSd]=useState(savedState?.sd||1);
  const save=(a,b,c,d)=>onSaveState({tf:a,pf:b,sb:c,sd:d});
  const setTF=v=>{setTf(v);save(v,pf,sb,sd);}; const setPF=v=>{setPf(v);save(tf,v,sb,sd);};
  const tSort=col=>{const nd=sb===col?-sd:col==="sort_key"?1:-1;setSb(col);setSd(nd);save(tf,pf,col,nd);};
  const positions=Object.keys(player.positions).sort();

  const filtered=useMemo(()=>player.match_list
    .filter(m=>(tf==="ALL"||m.team===tf)&&(pf==="ALL"||m.position===pf))
    .sort((a,b)=>{let av=a[sb],bv=b[sb];if(sb==="sort_key")return sd*(av>bv?1:av<bv?-1:0);if(typeof av==="string")return sd*av.localeCompare(bv);return sd*((av??-1)-(bv??-1));})
  ,[player,tf,pf,sb,sd]);

  const byTeam={};
  for(const t of player.teams){
    const tm=player.match_list.filter(m=>m.team===t);
    const w=tm.filter(m=>m.result==="W").length,l=tm.length-w;
    const rated=tm.filter(m=>m.opponent_rating&&player.rating);
    const avgDiff=rated.length>0?Math.round(rated.reduce((s,m)=>s+(m.opponent_rating-player.rating),0)/rated.length*1000)/1000:null;
    const isSub=!(player.roster_teams&&player.roster_teams[t]);
    byTeam[t]={w,l,matches:tm.length,avgDiff,isSub};
  }

  return <div>
    <button style={S.backBtn} onClick={onBack}>← Back</button>
    <div style={{marginTop:14,...S.card,padding:22}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:18,flexWrap:"wrap",gap:10}}>
        <div>
          <div style={{display:"flex",alignItems:"center",gap:10,flexWrap:"wrap",marginBottom:4}}>
            <h2 style={{margin:0,fontSize:20,fontWeight:800}}>{player.name}</h2>
            <RatingChip rating={player.rating}/>
          </div>
          {player.pre_season_rating&&player.rating&&<div style={{fontSize:12,color:"#64748b",marginBottom:2}}>
            Pre-season: {player.pre_season_rating.toFixed(3)} → Current: {player.rating.toFixed(3)}
            {player.rating_change!==null&&player.rating_change!==0&&<span style={{marginLeft:6}}><RatingDiffBadge diff={player.rating_change}/></span>}
          </div>}
          {player.primary_team&&<div style={{fontSize:12,color:"#94a3b8"}}>Primary team: <b style={{color:TEAM_COLORS[player.primary_team]}}>{player.primary_team}</b></div>}
        </div>
        <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
          {player.teams.map(t=>{
            const isPrimary=t===player.primary_team;
            const isSub=byTeam[t]?.isSub||false;
            return <TeamBadge key={t} team={t} isPrimary={isPrimary} isSub={isSub} onClick={()=>onTeamClick(t)}/>;
          })}
        </div>
      </div>

      <div style={{display:"flex",gap:10,marginBottom:20,flexWrap:"wrap"}}>
        {[{v:player.matches,l:"Matches",c:"#6366f1"},{v:player.wins,l:"Wins",c:"#16a34a"},{v:player.losses,l:"Losses",c:"#dc2626"},{v:player.win_pct+"%",l:"Win Rate",c:"#0891b2"}].map(s=>(
          <div key={s.l} style={S.statBox(s.c)}><div style={S.statVal(s.c)}>{s.v}</div><div style={S.statLabel}>{s.l}</div></div>
        ))}
      </div>

      {/* Position breakdown */}
      <div style={{marginBottom:20}}>
        <div style={S.sectionTitle}>Record by Roster Position</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:10}}>
          {positions.map(pos=>{
            const pd=player.positions[pos]; const tot=pd.wins+pd.losses;
            const pct=tot?Math.round(pd.wins/tot*100):0;
            const c=pct>50?"#16a34a":pct===50?"#d97706":"#dc2626";
            return <div key={pos} style={{background:"#f8fafc",border:"1px solid #e2e8f0",borderRadius:8,padding:"10px 14px",minWidth:155}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
                <PosBadge pos={pos} isSub={false}/>
                <span style={{fontSize:11,color:c,fontWeight:700}}>{pct}%</span>
              </div>
              <div style={{fontSize:13,marginBottom:4}}><span style={S.resultW}>{pd.wins}W</span><span style={{color:"#94a3b8",margin:"0 3px"}}>–</span><span style={S.resultL}>{pd.losses}L</span><span style={{color:"#94a3b8",fontSize:11,marginLeft:5}}>{tot}</span></div>
              <WinBar wins={pd.wins} losses={pd.losses}/>
              {pd.avg_rd!==null&&pd.rd_cnt>0&&<div style={{fontSize:11,color:"#64748b",marginTop:5}}>Avg opp Δ: <RatingDiffBadge diff={pd.avg_rd}/> <span style={{color:"#94a3b8"}}>({pd.rd_cnt})</span></div>}
            </div>;
          })}
        </div>
      </div>

      {/* Per-team summary */}
      <div style={{marginBottom:20}}>
        <div style={S.sectionTitle}>Record by Team</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:10}}>
          {player.teams.map(t=>{
            const ts=byTeam[t]; const pct=ts.w+ts.l>0?Math.round(ts.w/(ts.w+ts.l)*100):0;
            const isPrimary=t===player.primary_team;
            return <div key={t} style={{background:"#f8fafc",border:`${isPrimary?2:1}px solid ${TEAM_COLORS[t]}${isPrimary?"":"55"}`,borderRadius:8,padding:"10px 14px",minWidth:160}}>
              <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:5}}>
                <span style={{fontSize:13,fontWeight:600,color:TEAM_COLORS[t],cursor:"pointer"}} onClick={()=>onTeamClick(t)}>
                  {isPrimary?"★ ":""}{t}
                </span>
                {ts.isSub&&<PosBadge pos="sub" isSub={true}/>}
              </div>
              <div style={{fontSize:13,marginBottom:3}}><span style={S.resultW}>{ts.w}W</span><span style={{color:"#94a3b8",margin:"0 3px"}}>–</span><span style={S.resultL}>{ts.l}L</span><span style={{color:"#94a3b8",fontSize:11,marginLeft:5}}>{pct}%</span></div>
              {ts.avgDiff!==null&&<div style={{fontSize:11,color:"#64748b"}}>Avg opp Δ: <RatingDiffBadge diff={ts.avgDiff}/></div>}
            </div>;
          })}
        </div>
      </div>

      {/* Match log */}
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10,flexWrap:"wrap",gap:8}}>
          <div style={S.sectionTitle}>Matches ({filtered.length})</div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            <select value={tf} onChange={e=>setTF(e.target.value)} style={S.select}>{["ALL",...player.teams].map(t=><option key={t} value={t}>{t==="ALL"?"All Teams":t}</option>)}</select>
            <select value={pf} onChange={e=>setPF(e.target.value)} style={S.select}>{["ALL",...positions].map(p=><option key={p} value={p}>{p==="ALL"?"All Pos":p}</option>)}</select>
          </div>
        </div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead><tr>
              <SortTh label="Date/Time" col="sort_key" sortBy={sb} sortDir={sd} onSort={tSort}/>
              <SortTh label="Pos" col="position" sortBy={sb} sortDir={sd} onSort={tSort}/>
              <th style={S.th}>Playing For</th>
              <th style={S.th}>vs</th>
              <SortTh label="Opponent" col="opponent_name" sortBy={sb} sortDir={sd} onSort={tSort}/>
              <SortTh label="Opp Rating" col="opponent_rating" sortBy={sb} sortDir={sd} onSort={tSort} right/>
              <th style={S.th}>Score</th>
              <SortTh label="Result" col="result" sortBy={sb} sortDir={sd} onSort={tSort}/>
              <th style={S.th}>Rating Δ</th>
              <th style={S.th}>▶</th>
            </tr></thead>
            <tbody>
              {filtered.map((m,i)=>{
                const diff=ratingDiff(player.rating,m.opponent_rating);
                const myTeamIsPrimary=m.team===player.primary_team;
                const oppTeamIsPlayersPrimary=false; // not applicable here
                return <tr key={m.match_id} style={{background:i%2===0?"#fff":"#fafafa"}}>
                  <td style={S.td}><span style={{fontSize:12}}>{m.date}</span>{m.time&&<span style={{color:"#94a3b8",fontSize:11,marginLeft:5}}>{m.time}</span>}</td>
                  <td style={S.td}><PosBadge pos={m.position} isSub={m.is_sub}/></td>
                  <td style={S.td}>
                    <span onClick={()=>onTeamClick(m.team)} style={{...S.badge(TEAM_COLORS[m.team]),cursor:"pointer"}}>
                      {myTeamIsPrimary?"★ ":""}{m.team}
                    </span>
                  </td>
                  <td style={S.td}>
                    <span onClick={()=>onTeamClick(m.opponent_team)} style={{...S.badge(TEAM_COLORS[m.opponent_team]||"#888"),cursor:"pointer",fontSize:11}}>{m.opponent_team}</span>
                  </td>
                  <td style={S.td}>
                    <span onClick={()=>onPlayerClick(m.opponent_id)} style={S.link}>{m.opponent_name}</span>
                    {m.opponent_is_sub&&<span style={{fontSize:11,color:"#92400e",fontStyle:"italic",marginLeft:4}}>(sub)</span>}
                  </td>
                  <td style={S.tdR}>{m.opponent_rating?<span style={{fontSize:12,fontWeight:600}}>{m.opponent_rating.toFixed(3)}</span>:<span style={{color:"#94a3b8",fontSize:12}}>—</span>}</td>
                  <td style={{...S.td,fontFamily:"monospace",fontSize:11,whiteSpace:"nowrap"}}>{m.score}</td>
                  <td style={S.td}><span style={m.result==="W"?S.resultW:S.resultL}>{m.result==="W"?"WIN":"LOSS"}</span></td>
                  <td style={S.td}><RatingDiffBadge diff={diff}/></td>
                  <td style={S.td}><YouTubeIcon url={m.youtube}/></td>
                </tr>;
              })}
            </tbody>
          </table>
          {filtered.length===0&&<div style={{padding:20,color:"#94a3b8",textAlign:"center"}}>No matches match filters.</div>}
        </div>
      </div>
    </div>
  </div>;
}

// ─── Player List ──────────────────────────────────────────────────────────────
function PlayerListView({ onPlayerClick, onTeamClick, savedState, onSaveState }) {
  const [search,setSearch]=useState(savedState?.search||"");
  const [tf,setTf]=useState(savedState?.tf||"ALL");
  const [sb,setSb]=useState(savedState?.sb||"matches");
  const [sd,setSd]=useState(savedState?.sd||-1);
  const save=(s,t,sb,sd)=>onSaveState({search:s,tf:t,sb,sd});
  const toggleSort=col=>{const nd=sb===col?-sd:-1;setSb(col);setSd(nd);save(search,tf,col,nd);};
  const filtered=useMemo(()=>PLAYERS
    .filter(p=>p.name.toLowerCase().includes(search.toLowerCase())&&(tf==="ALL"||p.teams.includes(tf)))
    .sort((a,b)=>{const av=sb==="name"?a.name:a[sb],bv=sb==="name"?b.name:b[sb];if(typeof av==="string")return sd*av.localeCompare(bv);return sd*((av??-999)-(bv??-999));})
  ,[search,tf,sb,sd]);

  return <div>
    <div style={{display:"flex",gap:10,marginBottom:14,flexWrap:"wrap"}}>
      {[{v:PLAYERS.length,l:"Players",c:"#2563eb"},{v:387,l:"Matches",c:"#7c3aed"},{v:9,l:"Teams",c:"#0891b2"},{v:346,l:"Videos",c:"#dc2626"}].map(s=>(
        <div key={s.l} style={{...S.card,...S.statBox(s.c),padding:"10px 18px",minWidth:95}}><div style={S.statVal(s.c)}>{s.v}</div><div style={S.statLabel}>{s.l}</div></div>
      ))}
    </div>
    <div style={{marginBottom:12,display:"flex",gap:6,flexWrap:"wrap"}}>
      {ALL_TEAMS.map(t=><span key={t} onClick={()=>onTeamClick(t)} style={{...S.badge(TEAM_COLORS[t]),cursor:"pointer",fontSize:11}}>{t}</span>)}
    </div>
    <div style={{display:"flex",gap:10,marginBottom:12,flexWrap:"wrap"}}>
      <input value={search} onChange={e=>{setSearch(e.target.value);save(e.target.value,tf,sb,sd);}} placeholder="Search player..." style={{...S.input,flex:1,minWidth:160}}/>
      <select value={tf} onChange={e=>{setTf(e.target.value);save(search,e.target.value,sb,sd);}} style={S.select}>
        <option value="ALL">All Teams</option>{ALL_TEAMS.map(t=><option key={t} value={t}>{t}</option>)}
      </select>
    </div>
    <div style={{...S.card,overflow:"hidden"}}>
      <div style={{overflowX:"auto"}}>
        <table style={{width:"100%",borderCollapse:"collapse"}}>
          <thead><tr>
            <th style={{...S.th,width:32}}>#</th>
            <SortTh label="Player" col="name" sortBy={sb} sortDir={sd} onSort={toggleSort}/>
            <SortTh label="Rating" col="rating" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
            <SortTh label="Δ Rating" col="rating_change" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
            <SortTh label="MP" col="matches" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
            <SortTh label="W" col="wins" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
            <SortTh label="L" col="losses" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
            <SortTh label="Win%" col="win_pct" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
            <th style={S.th}>Positions</th>
            <th style={S.th}>Teams</th>
          </tr></thead>
          <tbody>
            {filtered.map((p,i)=>(
              <tr key={p.pid} style={{background:i%2===0?"#fff":"#f8fafc"}}>
                <td style={{...S.td,color:"#94a3b8",fontSize:11}}>{i+1}</td>
                <td style={S.td}><span onClick={()=>onPlayerClick(p.pid)} style={S.link}>{p.name}</span></td>
                <td style={S.tdR}><RatingChip rating={p.rating}/></td>
                <td style={S.tdR}>{p.rating_change!==null&&p.rating_change!==undefined?<RatingDiffBadge diff={p.rating_change}/>:<span style={{color:"#94a3b8",fontSize:12}}>—</span>}</td>
                <td style={{...S.tdR,fontWeight:600}}>{p.matches}</td>
                <td style={{...S.tdR,color:"#16a34a",fontWeight:700}}>{p.wins}</td>
                <td style={{...S.tdR,color:"#dc2626",fontWeight:700}}>{p.losses}</td>
                <td style={{...S.tdR,...S.pct(p.win_pct)}}>{p.win_pct}%</td>
                <td style={S.td}><div style={{display:"flex",gap:3,flexWrap:"wrap"}}>
                  {Object.entries(p.positions).sort().map(([pos,pd])=>(
                    <span key={pos} style={{display:"inline-flex",alignItems:"center",gap:3}}>
                      <PosBadge pos={pos} isSub={false}/>
                      <span style={{color:pd.wins>pd.losses?"#16a34a":pd.losses>pd.wins?"#dc2626":"#64748b",fontSize:11}}>{pd.wins}-{pd.losses}</span>
                    </span>
                  ))}
                </div></td>
                <td style={S.td}><div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
                  {p.teams.map(t=>{
                    const isPrimary=t===p.primary_team;
                    const isSub=!(p.roster_teams&&p.roster_teams[t]);
                    return <TeamBadge key={t} team={t} isPrimary={isPrimary} isSub={isSub&&!isPrimary} onClick={()=>onTeamClick(t)}/>;
                  })}
                </div></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div style={{padding:"7px 12px",fontSize:12,color:"#94a3b8",borderTop:"1px solid #f1f5f9"}}>Showing {filtered.length} of {PLAYERS.length} players</div>
    </div>
  </div>;
}

// ─── Team List ────────────────────────────────────────────────────────────────
function TeamListView({ onTeamClick, savedState, onSaveState }) {
  const [sb,setSb]=useState(savedState?.sb||"wins");
  const [sd,setSd]=useState(savedState?.sd||-1);
  const save=(sb,sd)=>onSaveState({sb,sd});
  const toggleSort=col=>{const nd=sb===col?-sd:-1;setSb(col);setSd(nd);save(col,nd);};

  const teamStats=useMemo(()=>ALL_TEAMS.map(t=>{
    const players=PLAYERS.filter(p=>p.teams.includes(t));
    const scMatches=Object.values(SCORECARDS).filter(sc=>sc.home_team===t||sc.visit_team===t);
    const wins=scMatches.filter(sc=>(sc.home_team===t&&sc.home_won>sc.visit_won)||(sc.visit_team===t&&sc.visit_won>sc.home_won)).length;
    const rAvgs=scMatches.map(sc=>sc.home_team===t?sc.home_roster_avg:sc.visit_roster_avg).filter(Boolean);
    const lAvgs=scMatches.map(sc=>sc.home_team===t?sc.home_avg_rating:sc.visit_avg_rating).filter(Boolean);
    const rAvg=rAvgs.length?Math.round(rAvgs.reduce((a,b)=>a+b,0)/rAvgs.length*1000)/1000:null;
    const lAvg=lAvgs.length?Math.round(lAvgs.reduce((a,b)=>a+b,0)/lAvgs.length*1000)/1000:null;
    const totalSubs=scMatches.reduce((s,sc)=>s+(sc.home_team===t?sc.home_sub_count:sc.visit_sub_count),0);
    const matchesWithSubs=scMatches.filter(sc=>(sc.home_team===t&&sc.home_sub_count>0)||(sc.visit_team===t&&sc.visit_sub_count>0)).length;
    const indiv=players.flatMap(p=>p.match_list.filter(m=>m.team===t));
    const seen=new Set(); const uniq=indiv.filter(m=>{if(seen.has(m.match_id))return false;seen.add(m.match_id);return true;});
    const iw=uniq.filter(m=>m.result==="W").length;
    return {name:t,players:players.length,wins,losses:scMatches.length-wins,total:scMatches.length,pct:scMatches.length?Math.round(wins/scMatches.length*100):0,rAvg,lAvg,totalSubs,matchesWithSubs,indivWins:iw,indivLosses:uniq.length-iw};
  }).sort((a,b)=>{const av=a[sb],bv=b[sb];if(typeof av==="string")return sd*av.localeCompare(bv);return sd*((av??-999)-(bv??-999));}),[sb,sd]);

  return <div style={{...S.card,overflow:"hidden"}}>
    <div style={{overflowX:"auto"}}>
      <table style={{width:"100%",borderCollapse:"collapse"}}>
        <thead><tr>
          <SortTh label="Team" col="name" sortBy={sb} sortDir={sd} onSort={toggleSort}/>
          <SortTh label="W" col="wins" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="L" col="losses" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="Win%" col="pct" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="Indiv W" col="indivWins" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="Indiv L" col="indivLosses" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="Roster Avg" col="rAvg" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="Lineup Avg" col="lAvg" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="Sub Uses" col="totalSubs" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
          <SortTh label="Matches w/Subs" col="matchesWithSubs" sortBy={sb} sortDir={sd} onSort={toggleSort} right/>
        </tr></thead>
        <tbody>
          {teamStats.map((t,i)=>(
            <tr key={t.name} onClick={()=>onTeamClick(t.name)} style={{background:i%2===0?"#fff":"#f8fafc",cursor:"pointer"}}
              onMouseEnter={e=>e.currentTarget.style.background="#eff6ff"}
              onMouseLeave={e=>e.currentTarget.style.background=i%2===0?"#fff":"#f8fafc"}>
              <td style={S.td}><div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:10,height:22,borderRadius:3,background:TEAM_COLORS[t.name]}}/>
                <span style={{fontWeight:700,color:TEAM_COLORS[t.name]}}>{t.name}</span>
              </div></td>
              <td style={{...S.tdR,color:"#16a34a",fontWeight:700}}>{t.wins}</td>
              <td style={{...S.tdR,color:"#dc2626",fontWeight:700}}>{t.losses}</td>
              <td style={{...S.tdR,...S.pct(t.pct)}}>{t.pct}%</td>
              <td style={{...S.tdR,color:"#16a34a"}}>{t.indivWins}</td>
              <td style={{...S.tdR,color:"#dc2626"}}>{t.indivLosses}</td>
              <td style={S.tdR}>{t.rAvg?<span style={{fontSize:12,fontWeight:600,color:"#0891b2"}}>{t.rAvg.toFixed(3)}</span>:<span style={{color:"#94a3b8"}}>—</span>}</td>
              <td style={S.tdR}>{t.lAvg?<b style={{fontSize:12,color:"#15803d"}}>{t.lAvg.toFixed(3)}</b>:<span style={{color:"#94a3b8"}}>—</span>}</td>
              <td style={S.tdR}>{t.totalSubs>0?<span style={{background:"#fefce8",color:"#854d0e",border:"1px solid #fde047",borderRadius:4,padding:"1px 7px",fontSize:11,fontWeight:700}}>{t.totalSubs}</span>:<span style={{color:"#94a3b8"}}>0</span>}</td>
              <td style={S.tdR}>{t.matchesWithSubs>0?<span style={{fontSize:12,color:"#92400e"}}>{t.matchesWithSubs}</span>:<span style={{color:"#94a3b8"}}>0</span>}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  </div>;
}

// ─── App Shell ────────────────────────────────────────────────────────────────
export default function App() {
  const [view,setView]=useState("players");
  const [selPlayer,setSelPlayer]=useState(null);
  const [selTeam,setSelTeam]=useState(null);
  const [history,setHistory]=useState([]);
  const vs=useRef({});
  const gs=key=>vs.current[key]||{};
  const ss=(key,state)=>{vs.current[key]={...vs.current[key],...state};};
  const nav=(nv,data={})=>{setHistory(h=>[...h,{view,player:selPlayer,team:selTeam}]);setView(nv);if(data.p)setSelPlayer(data.p);if(data.t)setSelTeam(data.t);};
  const goBack=()=>{const prev=history[history.length-1];if(prev){setHistory(h=>h.slice(0,-1));setView(prev.view);setSelPlayer(prev.player);setSelTeam(prev.team);}else setView("players");};
  const openPlayer=pid=>{const p=PLAYER_MAP[pid];if(p)nav("player",{p});};
  const openTeam=name=>nav("team",{t:name});

  return <div style={S.page}>
    <div style={S.header}>
      <div style={{display:"flex",alignItems:"center",gap:12,padding:"8px 0"}}>
        <div style={{background:"#000",borderRadius:6,padding:"2px 4px",display:"inline-flex",alignItems:"center"}}><img src={LOGO_B64} alt="Maine Rocks!" style={{height:40,width:"auto"}}/></div>
        <div>
          <div style={{fontSize:17,fontWeight:800,letterSpacing:0.3}}>PCS Maine Squash Winter League 2026</div>
          <div style={{fontSize:12,opacity:0.7,marginTop:1}}>Maine Rocks! · 9 Teams · 387 Matches · 346 Videos</div>
        </div>
      </div>
      <div style={S.nav}>
        <button style={S.navBtn(view==="players"||view==="player")} onClick={()=>{setView("players");setHistory([]);}}>Players</button>
        <button style={S.navBtn(view==="teams"||view==="team")} onClick={()=>{setView("teams");setHistory([]);}}>Teams</button>
      </div>
    </div>
    <div style={S.body}>
      {view==="players"&&<PlayerListView onPlayerClick={openPlayer} onTeamClick={openTeam} savedState={gs("players")} onSaveState={s=>ss("players",s)}/>}
      {view==="teams"&&<TeamListView onTeamClick={openTeam} savedState={gs("teams")} onSaveState={s=>ss("teams",s)}/>}
      {view==="player"&&selPlayer&&<PlayerView player={selPlayer} onBack={goBack} onTeamClick={openTeam} onPlayerClick={openPlayer} savedState={gs("player_"+selPlayer.pid)} onSaveState={s=>ss("player_"+selPlayer.pid,s)}/>}
      {view==="team"&&selTeam&&<TeamView teamName={selTeam} onBack={goBack} onPlayerClick={openPlayer} savedState={gs("team_"+selTeam)} onSaveState={s=>ss("team_"+selTeam,s)}/>}
    </div>
  </div>;
}
